        ENDPARAF                                                              = 7476,  -- ENDPARAF#
        WHICH_SERVICE_DO_YOU_REQUEST_BUY_SELL_ITEMS                           = 7477,  -- Which service do you request? Buy/Sell items. Teleportation. Nothing.
        DO_YOU_REALLY_WISH_TO_BE_TELEPORTED_YES                               = 7478,  -- Do you really wish to be teleported? Yes. Teleport with gil. Teleport with conquest points. No.
        WELCOME_TO_THE_BORDER_SHOP_IF_YOU_TRADE                               = 7479,  -- Welcome to the border shop! If you trade me unused equipment, I'll add their value to your country's region points!
        IT_SHOULD_PLEASE_YOU_TO_KNOW_THAT_I                                   = 7480,  -- It should please you to know that I now also deal in %. Bigger pieces will earn you more points for your nation, and I'll even toss some gil into the equation!
        I_SEE_THAT_YOUR_HOME_COUNTRY_HAS_CONTROL                              = 7481,  -- I see that your home country has control of this region. Feel free to browse through my wares.
        I_SEE_THAT_YOUR_HOME_COUNTRY_IS_ALLIES                                = 7482,  -- I see that your home country is allies with the country in control of this region. Feel free to browse through my wares.
        I_CAN_TELEPORT_YOU_TO_YOUR_HOME_COUNTRY                               = 7483,  -- I can teleport you to your home country for # gil or # conquest [point/points].
        WORD_HAS_IT_THAT_THE_ENTIRE_SET_OF                                    = 7484,  -- Word has it that the entire set of mog tablets has been recovered. Oh, happy day! In honor of the occasion, I can teleport you to your home country free of charge.
        I_AM_TERRIBLY_SORRY_BUT_IT_SEEMS_AS                                   = 7485,  -- I am terribly sorry, but it seems as if you do not have enough gil.
        I_AM_TERRIBLY_SORRY_BUT_IT_SEEMS_AS_2                                 = 7486,  -- I am terribly sorry, but it seems as if you do not have enough conquest points.
        HOWEVER_DUE_TO_YOUR_HOME_COUNTRY_S_LACK                               = 7487,  -- However, due to your home country's lack of influence in the region, this is the only transaction I am authorized to perform with you at the moment.
        I_AM_LOOKING_FORWARD_TO_DOING_BUSINESS_WITH                           = 7488,  -- I am looking forward to doing business with you again in the future!
        THANK_YOU_THIS_WILL_INCREASE_YOUR_NATION_S                            = 7489,  -- Thank you. This will increase your nation's region points by a small amount. If you have anything else, by all means, trade them to me.
        THANK_YOU_THIS_WILL_INCREASE_YOUR_NATION_S_2                          = 7490,  -- Thank you. This will increase your nation's region points moderately. If you have anything else, by all means, trade them to me.
        THANK_YOU_THIS_WILL_INCREASE_YOUR_NATION_S_3                          = 7491,  -- Thank you. This will increase your nation's region points greatly. If you have anything else, by all means, trade them to me.
        I_COULD_NOT_ACCEPT_ONE_OR_MORE_ITEMS                                  = 7492,  -- I could not accept one or more items you tried to trade me. Please remove those items and try again.
        SORRY_I_CAN_ONLY_TAKE_CERTAIN_TYPES_OF                                = 7493,  -- Sorry. I can only take certain types of weapons, shields, or armor.
        THANK_YOU_THIS_WILL_INCREASE_YOUR_NATION_S_4                          = 7494,  -- Thank you. This will increase your nation's region points [by a small amount/moderately/greatly]. For this transaction I will also furnish you with # gil.
        MY_APOLOGIES_BUT_THIS_TYPE_OF_ITEM_NEEDS                              = 7495,  -- My apologies, but this type of item needs to be individually appraised. Please trade them to me one at a time.
        DEBUG_BACK_TO_HOMETOWN                                                = 7496,  -- (DEBUG) Back to hometown!
        WHAT_DO_YOU_WANT_WOULD_YOU_CAST_SIGNET                                = 7497,  -- What do you want? Would you cast Signet on me? I'd like to set my home point here. Nothing.
        WHAT_DO_YOU_WANT_PAY_GIL_AND_SET                                      = 7498,  -- What do you want? Pay # gil and set my home point here. Nothing.
        YOUR_HOME_POINT_HAS_BEEN_SET                                          = 7499,  -- Your home point has been set.
        YOU_DO_NOT_HAVE_ENOUGH_GIL_TO_SET                                     = 7500,  -- You do not have enough gil to set your home point here.
        I_WILL_SET_YOUR_HOME_POINT_HERE                                       = 7501,  -- I will set your home point here.
        WE_ARE_CURRENTLY_ON_A_BEASTMAN_PURGING_CAMPAIGN                       = 7502,  -- We are currently on a beastman-purging campaign. We support adventurers from all nations. Do your best to rid the world of those vile creatures.
        WE_ARE_CURRENTLY_CONDUCTING_AN_INTERNATIONAL_EXCHANGE_CAMPAIGN        = 7503,  -- We are currently conducting an international exchange campaign. You may spend your conquest points to purchase items from foreign guards.
        THANKS_TO_YOU_OUR_NATION_IS_NOW_FIRST                                 = 7504,  -- Thanks to you, our nation is now first in the conquest race! Here is a small token of our appreciation.
        ADVENTURERS_FROM_NATIONS_THAT_ARE_RANKED_HIGHER_THAN                  = 7505,  -- Adventurers from nations that are ranked higher than ours in the conquest race may purchase items from us, but at a higher rate.
        YOU_CANNOT_CURRENTLY_PURCHASE_THIS_ITEM_PLEASE_CHOOSE                 = 7506,  -- You cannot currently purchase this item. Please choose another.
        CURRENTLY_OUR_NATION_IS_DISPATCHING_EXPEDITIONARY_FORCES_ACROSS       = 7507,  -- Currently our nation is dispatching Expeditionary Forces across Vana'diel, and requests the participation of brave adventurers such as yourself.
        REQUIREMENTS_FOR_PARTICIPATING_IN_AN_E_F_ARE                          = 7508,  -- Requirements for participating in an E.F. are simple. Your party must consist of # members. Each member must be from this country, rank 3 or higher, and have reached a sufficient level.
        ONCE_YOUR_PARTY_IS_READY_COME_TO_ME                                   = 7509,  -- Once your party is ready, come to me and I will teleport you to the nearest outpost.
        THERE_YOU_WILL_RECEIVE_AN_INSIGNIA_OF_THE                             = 7510,  -- There, you will receive an insignia of the Expeditionary Force. When you succeed in taking control of the area, you can exchange the insignia for your reward.
        JOIN_THE_E_F_IN_JOIN_THE_E                                            = 7511,  -- Join the E.F. in [Ronfaure/Zulkheim/Norvallen/Gustaberg/Derfland/Sarutabaruta/Kolshushu/Aragoneu/Fauregandi/Valdeaunia/Qufim/Li'Telor/Kuzotz/Vollbow/The Elshimo Lowlands/The Elshimo Uplands]? Join the E.F. Not this time.
        YOUR_PARTY_DOESN_T_HAVE_ENOUGH_MEMBERS_OR                             = 7512,  -- Your party doesn't have enough members, or some of the members are not in this area. Gather all those who are participating and return here.
        ONE_OF_YOUR_PARTY_MEMBERS_IS_NOT_A                                    = 7513,  -- One of your party members is not a citizen of this country. We do not allow any foreign participants in the E.F.
        ONE_OF_YOUR_PARTY_MEMBERS_HAS_NOT_ACHIEVED                            = 7514,  -- One of your party members has not achieved rank level 3. We cannot reveal any of our tactical strategies to those who have not shown their loyalty to our country.
        ONE_OF_YOUR_PARTY_MEMBERS_IS_BELOW_LEVEL                              = 7515,  -- One of your party members is below level #. For the safety of the adventurer and those accompanying him or her, we cannot allow anyone below the limit to participate in the E.F.
