        AND_ACTUALLY_I_BELIEVE_THE_OLD_MAN_SAID                               = 11597,  -- And actually, I believe the old man said something similar.
        HUH_I_HAD_A_FEELING_YOU_MIGHT_SAY                                     = 11598,  -- Huh! I had a feeling you might say that!
