        BESIDES_I_HEAR_THAT_THE_WEAPON_WILL_DEVOUR                            = 11600,  -- Besides, I hear that the weapon will devour the soul of those who wield it!
        AND_ACTUALLY_I_BELIEVE_THE_OLD_MAN_SAID_2                             = 11601,  -- And actually, I believe the old man said something similar.
        I_NEVER_THOUGHT_THE_BLACK_SWORD_WOULD_BE                              = 11602,  -- I never thought the black sword would be passed down to me. It was quite the shock!
        W_WAS_IT_THE_ONE_DESTROYED_BY_THE                                     = 11603,  -- W-was it the one destroyed by the b-bomb?
        INDEED_THAT_WAS_QUITE_THE_SPECIAL_ITEM                                = 11604,  -- Indeed! That was quite the special item!
        AFTER_DEALING_THE_FINAL_BLOW_TO_CHAOS_IN                              = 11605,  -- After dealing the final blow to Chaos in Valhalla, it just went off!
        IT_WAS_COVERED_IN_CHAOS_S_BLOOD_AND                                   = 11606,  -- It was covered in Chaos's blood, and that was the cause of everything...
        ACTUALLY_YOUR_BROTHER_MENTIONED_THAT_TOO                              = 11607,  -- Actually, your brother mentioned that too.
