        G_GLOOM_PHANTOM_IS_MUCH_BETTER_NOW                                    = 11615,  -- G-Gloom Phantom is much better now.
        AND_AS_FOR_MY_WORTHLESS_BROTHER_KIPDRIX                               = 11616,  -- And as for my worthless brother, Kipdrix...
        I_HEARD_THAT_HE_CAUSED_YOU_ALL_KINDS                                  = 11617,  -- I heard that he caused you all kinds of trouble!
