        WELL_EITHER_WAY_THERE_S_SOMETHING_I_NEED                              = 11624,  -- Well, either way, there's something I need to ask you.
        HUH_I_HEARD_THAT_MY_BROTHER_KIPDRIX_BROUGHT                           = 11625,  -- Huh!? I heard that my brother, Kipdrix, brought a bomb to Movalpolos and caused all kinds of trouble!
        SO_I_M_ASKING_FOR_YOUR_FORGIVENESS_GIVEN                              = 11626,  -- So I'm asking for your forgiveness, given all the trouble we've caused you!
        YOU_RE_GOING_TO_FACE_CHAOS_IN_A                                       = 11627,  -- You're going to face Chaos in a battle to the death, right!?
        YOU_MUST_TAKE_THE_DESTINY_DESTROYERS_WITH_YOU                         = 11628,  -- You must take the Destiny Destroyers with you!
        W_WE_PROMISE_TO_DO_OUR_BEST                                           = 11629,  -- W-we promise to do our best!
